import{j as e}from"./vendor-react-BB9tsc3Z.js";import{M as t}from"./MobilePageLayout-BAnSXXtz.js";import"./vendor-misc-CEWPm66Y.js";import"./index-CBrXAMbW.js";import"./vendor-router-DqG_9oXp.js";import"./vendor-icons-DCGlAsJ-.js";import"./vendor-motion-CJwlNdkI.js";import"./vendor-socket-CmWqgDFt.js";const i={title:"আমাদের তথ্য কেন্দ্রে স্বাগতম",paragraphs:["JowaBuzz সম্পূর্ণ লাইসেন্সপ্রাপ্ত এবং নিয়ন্ত্রিত একটি অনলাইন গেমিং প্ল্যাটফর্ম, যা বাংলাদেশের খেলোয়াড়দের জন্য নিরাপদ, নির্ভরযোগ্য ও উচ্চমানের বিনোদন প্রদান করতে প্রতিশ্রুতিবদ্ধ।","আমরা আপনার ব্যক্তিগত তথ্য ও গোপনীয়তাকে সর্বোচ্চ গুরুত্ব দিই। JowaBuzz-এ আপনার ডেটা তৃতীয় পক্ষের সাথে শেয়ার করা হয় না এবং আমরা একটি নিরাপদ, ব্যক্তিগত পরিবেশ বজায় রাখতে কঠোর নিরাপত্তা ব্যবস্থা অনুসরণ করি।","আমাদের প্ল্যাটফর্মে রয়েছে স্পোর্টস বেটিং, লাইভ ক্যাসিনো, স্লট, ক্র্যাশ, টেবিল গেমস এবং আরও অনেক কিছু — সবকিছুই মোবাইল-ফার্স্ট অভিজ্ঞতায় উপভোগ করতে পারবেন।","আমাদের অভিজ্ঞ গ্রাহক সহায়তা দল ২৪/৭ উপলব্ধ। যেকোনো সময় জমা, উত্তোলন, অ্যাকাউন্ট বা গেম সংক্রান্ত প্রশ্নে আমরা আপনাকে সহায়তা করতে প্রস্তুত।","আমাদের লক্ষ্য হলো সেরা অনলাইন গেমিং অভিজ্ঞতা প্রদান করা — দ্রুত লেনদেন, স্থানীয় পেমেন্ট পদ্ধতি (bKash, Nagad, Rocket, Upay) এবং স্বচ্ছ, ন্যায্য সেবার মাধ্যমে।","JowaBuzz নিরাপদ পেমেন্ট পদ্ধতি প্রদান করে এবং KYC (Know Your Customer) ও AML (Anti-Money Laundering) নীতিমালা মেনে চলে, যাতে সকল খেলোয়াড়ের জন্য একটি নিরাপদ ও বিশ্বস্ত গেমিং পরিবেশ নিশ্চিত করা যায়।"]};function s(){return e.jsxs("section",{className:"info-page-section","aria-labelledby":"about-us-title",children:[e.jsxs("div",{className:"info-page-section__head",children:[e.jsx("h1",{id:"about-us-title",className:"info-page-section__title",children:i.title}),e.jsx("div",{className:"info-page-section__divider","aria-hidden":"true"})]}),e.jsx("div",{className:"info-page-section__body",children:i.paragraphs.map(a=>e.jsx("p",{className:"info-page-section__text",children:a},a.slice(0,32)))})]})}function m(){return e.jsx(t,{children:e.jsx("div",{className:"about-us-page mx-auto w-full max-w-3xl px-4 py-6 md:px-6 md:py-8",children:e.jsx(s,{})})})}export{m as default};
